#act-gigante .hint-btn:hover{background:#EEEDFE;}
#act-gigante .hint-popup{display:none;position:absolute;bottom:calc(100% + 8px);left:50%;transform:translateX(-50%);background:#26215C;color:#fff;font-size:12px;padding:7px 13px;border-radius:9px;z-index:20;pointer-events:none;max-width:220px;white-space:normal;text-align:center;line-height:1.4;}
