#ag-cel .ccaptura{background:#f4f1ff;border:2px dashed #AFA9EC;border-radius:14px;padding:.9rem 1rem;font-size:14px;color:#534AB7;margin-bottom:1.5rem;font-weight:600;line-height:1.5;}
#ag-cel .ccaptura .cam{font-size:36px;display:block;margin-bottom:6px;}

/* CONFETI */
