</style>
<p><!-- ACTIVIDAD --></p>
<div id="act-gigante"><span class="badge">✏️ Completa el dato</span>
<h2>¿Cuánto sabes del gigante?</h2>
<p class="instruccion">Escribe la palabra o número que falta en cada espacio. Toca 💡 si necesitas una pista. ¡Recibirás retroalimentación inmediata!</p>
<div class="estrellas" id="ag-estrellas"></div>
<div class="feedback-box" id="ag-fb"></div>
<div class="parrafo" id="ag-parrafo"></div>
<div class="acciones"><button class="pri" onclick="agVerificar()">✓ Verificar todo</button> <button class="sec" onclick="agReiniciar()">🔄 Volver a intentar</button></div>
</div>
<p><!-- OVERLAY FELICITACIONES --></p>
<div id="ag-overlay">
<div id="ag-cel">
<div class="trofeo">🏆</div>
<p class="ctitulo">¡Felicidades!</p>
<div class="cpuntaje" id="ag-cpuntaje"></div>
<p class="csub">Completaste todos los espacios correctamente.<br />¡Eres un verdadero experto en los gigantes de la informática!</p>
<div class="ccaptura"><span class="cam">📸</span> ¡Toma captura de pantalla de tu triunfo<br />y compártela con tu profe!</div>
<button class="pri" onclick="agCerrar()">Seguir practicando</button></div>
</div>
<p><!-- CONFETI --> <canvas id="ag-confetti"></canvas>
<script>
(function(){
  /* ── TEXTO Y PISTAS ── */
  var texto =
    'La Primera Generación de computadoras abarca el periodo entre @@1946@@ y 1956. ' +
    'El ENIAC fue presentado el 14 de febrero de 1946 y fue construido en la Universidad de @@Pensilvania@@. ' +
    'Ocupaba 140 m² y pesaba @@30@@ toneladas. ' +
    'Tenía @@18.000@@ tubos de vacío y podía resolver 5.000 sumas por @@segundo@@. ' +
    'Para "programar" el ENIAC había que reconectar físicamente sus @@cables@@, lo que podía tomar días. ' +
    'John von Neumann propuso en 1945 que un computador debería tener una Unidad Aritmético-Lógica, ' +
    'una Unidad de Control, una @@Memoria@@ y dispositivos de Entrada y Salida. ' +
    'El UNIVAC I fue el primer computador @@comercial@@, entregado el 31 de marzo de 1951. ' +
    'En 1952 el UNIVAC I predijo correctamente las @@elecciones@@ presidenciales de EE.UU. con solo el 1% de los votos contados. ' +
    'En total se vendieron @@46@@ unidades del UNIVAC I.';

  var pistas = [
    'Piensa en el año en que terminó la Segunda Guerra Mundial.',
    'Es un estado famoso en el noreste de Estados Unidos.',
    'Es un número entre 25 y 35 (en toneladas).',
    'Dieciocho mil — se escribe con punto como separador.',
    'Unidad de tiempo muy corta. ¡Tick!',
    'Los técnicos los reconectaban a mano, como enchufes eléctricos.',
    'Es donde el computador guarda datos e instrucciones.',
    'Quiere decir que se vendía al público en general.',
    'Evento político donde la gente elige a su presidente.',
    'Número entre 40 y 50.',
  ];

  /* ── CONSTRUIR PÁRRAFO ── */
  var blanks = [];
  var html = '';
  texto.split(/@@([^@]+)@@/).forEach(function(parte, idx){
    if(idx % 2 === 0){ html += parte; }
    else {
      var i = blanks.length;
      blanks.push(parte);
      var w = Math.max(65, parte.length * 13);
      html +=
        '<span class="blank-wrap" id="agbw'+i+'">' +
          '<input class="blank-input" id="agb'+i+'" type="text" placeholder="___" ' +
            'style="width:'+w+'px" oninput="agRevisar('+i+')" autocomplete="off" spellcheck="false"/>' +
          '<span class="blank-num">'+(i+1)+'</span>' +
          '<div class="hint-popup" id="aghp'+i+'">'+pistas[i]+'</div>' +
        '</span>' +
        '<button class="hint-btn" onclick="agHint(event,'+i+')" title="Ver pista">💡</button>';
    }
  });
  document.getElementById('ag-parrafo').innerHTML = html;

  /* ── ESTRELLAS ── */
  var sc = document.getElementById('ag-estrellas');
  blanks.forEach(function(_,i){ sc.innerHTML += '<span class="estrella" id="agst'+i+'">⭐</span>'; });

  /* ── PISTAS ── */
  var hintOpen = -1;
  window.agHint = function(e,i){
    e.stopPropagation();
    var el = document.getElementById('aghp'+i);
    if(hintOpen===i){ el.classList.remove('visible'); hintOpen=-1; return; }
    if(hintOpen>=0) document.getElementById('aghp'+hintOpen).classList.remove('visible');
    el.classList.add('visible'); hintOpen=i;
  };
  document.addEventListener('click',function(){
    if(hintOpen>=0){ document.getElementById('aghp'+hintOpen).classList.remove('visible'); hintOpen=-1; }
  });

  /* ── NORMALIZAR ── */
  function norm(s){
    return s.trim().toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
      .replace(/\s+/g,' ');
  }

  /* ── REVISAR UNO ── */
  window.agRevisar = function(i){
    var inp = document.getElementById('agb'+i);
    var st  = document.getElementById('agst'+i);
    var ok  = inp.value && norm(inp.value)===norm(blanks[i]);
    inp.className = inp.value ? 'blank-input '+(ok?'correcto':'incorrecto') : 'blank-input';
    st.className  = 'estrella'+(ok?' encendida':'');
    if(ok && hintOpen===i){ document.getElementById('aghp'+i).classList.remove('visible'); hintOpen=-1; }
    agCheckTodo();
  };

  /* ── VERIFICAR TODO ── */
  window.agVerificar = function(){
    blanks.forEach(function(_,i){ agRevisar(i); });
    var ok = blanks.filter(function(_,i){ return norm(document.getElementById('agb'+i).value)===norm(blanks[i]); }).length;
    if(ok < blanks.length){
      var fb = document.getElementById('ag-fb');
      fb.className='feedback-box sigue';
      fb.textContent='🌟 Llevas '+ok+' de '+blanks.length+' correctas. ¡Revisa los espacios en rojo e intenta de nuevo!';
    }
  };

  /* ── CHECK COMPLETO ── */
  function agCheckTodo(){
    var ok = blanks.every(function(_,i){ return norm(document.getElementById('agb'+i).value)===norm(blanks[i]); });
    if(ok){
      document.getElementById('ag-fb').className='feedback-box';
      setTimeout(function(){
        document.getElementById('ag-cpuntaje').textContent='⭐'.repeat(blanks.length);
        document.getElementById('ag-overlay').classList.add('show');
        agLanzarConfeti();
      },350);
    }
  }

  /* ── CERRAR ── */
  window.agCerrar = function(){
    document.getElementById('ag-overlay').classList.remove('show');
    agPararConfeti();
  };

  /* ── REINICIAR ── */
  window.agReiniciar = function(){
    blanks.forEach(function(_,i){
      var inp=document.getElementById('agb'+i);
      inp.value=''; inp.className='blank-input';
      document.getElementById('agst'+i).className='estrella';
    });
    document.getElementById('ag-fb').className='feedback-box';
    if(hintOpen>=0){ document.getElementById('aghp'+hintOpen).classList.remove('visible'); hintOpen=-1; }
  };

  /* ── CONFETI ── */
  var canvas=document.getElementById('ag-confetti');
  var ctx=canvas.getContext('2d');
  var particulas=[],animId=null;
  var COLS=['#7F77DD','#1D9E75','#EF9F27','#E24B4A','#AFA9EC','#FFD700','#FF85A1','#00C9A7'];

  function crearP(){
    return{x:Math.random()*canvas.width,y:-14,w:8+Math.random()*9,h:5+Math.random()*6,
      color:COLS[Math.floor(Math.random()*COLS.length)],
      rot:Math.random()*Math.PI*2,vx:(Math.random()-.5)*4,
      vy:2.5+Math.random()*3,vr:(Math.random()-.5)*.18,alpha:1};
  }

  function agLanzarConfeti(){
    canvas.width=window.innerWidth; canvas.height=window.innerHeight;
    particulas=[];
    for(var i=0;i<160;i++){ var p=crearP(); p.y=Math.random()*canvas.height*.4; particulas.push(p); }
    animar();
  }

  function animar(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    particulas.forEach(function(p){
      p.x+=p.vx; p.y+=p.vy; p.rot+=p.vr; p.vy+=.05;
      if(p.y>canvas.height*.75) p.alpha-=.018;
      ctx.save(); ctx.globalAlpha=Math.max(0,p.alpha);
      ctx.translate(p.x,p.y); ctx.rotate(p.rot);
      ctx.fillStyle=p.color; ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);
      ctx.restore();
    });
    particulas=particulas.filter(function(p){ return p.alpha>0; });
    if(particulas.length>0) animId=requestAnimationFrame(animar);
    else ctx.clearRect(0,0,canvas.width,canvas.height);
  }

  function agPararConfeti(){
    if(animId) cancelAnimationFrame(animId);
    ctx.clearRect(0,0,canvas.width,canvas.height); particulas=[];
  }
})();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

