.inf-nota{background:#f5eeff;border-left:4px solid #7f26d3;border-radius:0 10px 10px 0;padding:12px 18px;font-size:1rem;font-weight:500;color:#15203d;margin-bottom:1.6rem;animation:fadeUp 0.8s ease both;line-height:1.65}
